如果您需要取出鼠标选中的文字，您可以使用Windows原生的API来实现。下面是一个主要用于Windows平台的C++代码示例：

```c++
#include <windows.h>
#include <iostream>

HHOOK hHook;
KBDLLHOOKSTRUCT kbdStruct;

LRESULT CALLBACK mouseProc(int nCode, WPARAM wParam, LPARAM lParam) {
    PKBDLLHOOKSTRUCT p = (PKBDLLHOOKSTRUCT)lParam;

    if (wParam == WM_LBUTTONUP) {
        HWND foreground = GetForegroundWindow();
        DWORD pid;
        GetWindowThreadProcessId(foreground, &pid);

        HANDLE hProcess = OpenProcess(PROCESS_VM_READ | PROCESS_QUERY_INFORMATION, FALSE, pid);

        POINT p;
        if (!GetCursorPos(&p)) {
            return CallNextHookEx(hHook, nCode, wParam, lParam);
        }

        HWND hWnd = WindowFromPoint(p);
        if (!hWnd) {
            return CallNextHookEx(hHook, nCode, wParam, lParam);
        }

        DWORD dw;
        SendMessageTimeout(hWnd, WM_GETTEXTLENGTH, 0, 0, SMTO_ABORTIFHUNG, 1000, &dw);

        char* szText = new char[dw + 1]();

        SendMessageTimeout(hWnd, WM_GETTEXT, dw + 1, (LPARAM)szText, SMTO_ABORTIFHUNG, 1000, &dw);

        std::cout << "Selected Text: " << szText << std::endl;

        delete p;
        delete szText;
    }

    return CallNextHookEx(hHook, nCode, wParam, lParam);
}

int main() {
    HINSTANCE hInstance = GetModuleHandle(NULL);
    hHook = SetWindowsHookEx(WH_MOUSE_LL, mouseProc, hInstance, 0);

    MSG msg;
    while (GetMessage(&msg, NULL, 0, 0) != 0) {
        TranslateMessage(&msg);
        DispatchMessage(&msg);
    }

    return 0;
}
```

此代码示例使用Windows API提供的函数来获取输入焦点窗口句柄、获取鼠标指针所在的窗口句柄、获取窗口中鼠标选中的文本等。需要注意的是，此方法仅适用于Windows操作系统，并且需要管理员权限才能运行。
